refsection.programlisting:
grand("setsd",0);
// The number of observations
N = 100;
// The exact coefficients
B = [2;3;4]
// The input 1
X1min = 50;
X1max = 150;
X1=grand(N,1,"uin",X1min,X1max);
X1=gsort(X1,"g","i");
// The input 2
X2min = -500;
X2max = -200;
X2=grand(N,1,"uin",X2min,X2max);
X2=gsort(X2,"g","i");
// Make the observations
X = [X1,X2];
// Compute the ouput from the input
Y = B(1)+B(2)*X1+B(3)*X2;
// Add a normal noise to the output
sigma = 50;
e = grand(N,1,"nor",0,sigma);
Y = int(Y + e);
// Linear regression
B = scidoe_multilinreg(X,Y)
// Compare B (exact) with B (estimate)
[B,B]
L = B(1)+B(2)*X(:,1)+B(3)*X(:,2);
// Check visually
scf();
plot(Y,L,"bo");
plot(Y,Y,"r-");
xtitle("Linear Regression","Data","Linear Fit");
